   218→### 4. Update lib/work-utils.ts
   219→**File**: `.claude/hooks/lib/work-utils.ts`
   220→
   221→**Issues**:
   222→- Work file operations
   223→- May spawn processes for work coordination
   224→- File locking or synchronization
   225→
   226→**Solution:**
   227→```typescript
   228→import * as fs from 'fs';
   229→import * as path from 'path';
   230→import { paths } from './paths';
   231→import { PLATFORM } from './paths';
   232→
   233→export function createWorkFile(workId: string, data: any): void {
   234→  const workDir = paths.WORK_DIR;
   235→  const workFile = path.join(workDir, `${workId}.json`);
   236→
   237→  // Ensure directory exists (cross-platform mkdir -p)
   238→  if (!fs.existsSync(workDir)) {
   239→    fs.mkdirSync(workDir, { recursive: true });
   240→  }
   241→
   242→  // Write with proper error handling
   243→  try {
   244→    fs.writeFileSync(workFile, JSON.stringify(data, null, 2), 'utf8');
   245→  } catch (error) {
   246→    console.error(`Failed to create work file: ${error.message}`);
   247→    throw error;
   248→  }
   249→}
   250→
   251→export function lockWorkFile(workId: string): boolean {
   252→  const lockFile = path.join(paths.WORK_DIR, `${workId}.lock`);
   253→
   254→  try {
   255→    // Use exclusive flag for cross-platform file locking
   256→    const fd = fs.openSync(lockFile, 'wx');
   257→    fs.writeSync(fd, new Date().toISOString());
   258→    return true;
   259→  } catch (error) {
   260→    // File exists, already locked
   261→    return false;
   262→  }
   263→}
   264→```
