     1→/**
     2→ * Shared Time Utilities
     3→ *
     4→ * Consistent timestamp generation across the hook system.
     5→ * Reads timezone from settings.json via principal.timezone
     6→ * Used by: All hooks that need timestamps
     7→ */
     8→
     9→import { getPrincipal } from './identity';
    10→
    11→/**
    12→ * Get configured timezone from settings.json (defaults to UTC)
    13→ */
    14→function getTimezone(): string {
    15→  return getPrincipal().timezone || 'UTC';
    16→}
    17→
    18→/**
    19→ * Get full timestamp string: "YYYY-MM-DD HH:MM:SS TZ"
    20→ */
    21→export function getPSTTimestamp(): string {
    22→  const timezone = getTimezone();
    23→  const date = new Date();
    24→  const localDate = new Date(date.toLocaleString('en-US', { timeZone: timezone }));
    25→
    26→  const year = localDate.getFullYear();
    27→  const month = String(localDate.getMonth() + 1).padStart(2, '0');
    28→  const day = String(localDate.getDate()).padStart(2, '0');
    29→  const hours = String(localDate.getHours()).padStart(2, '0');
    30→  const minutes = String(localDate.getMinutes()).padStart(2, '0');
    31→  const seconds = String(localDate.getSeconds()).padStart(2, '0');
    32→
    33→  // Get short timezone name
    34→  const tzName = date.toLocaleString('en-US', { timeZone: timezone, timeZoneName: 'short' }).split(' ').pop() || 'UTC';
    35→
    36→  return `${year}-${month}-${day} ${hours}:${minutes}:${seconds} ${tzName}`;
    37→}
    38→
    39→/**
    40→ * Get date only: "YYYY-MM-DD"
    41→ */
    42→export function getPSTDate(): string {
    43→  const timezone = getTimezone();
    44→  const date = new Date();
    45→  const localDate = new Date(date.toLocaleString('en-US', { timeZone: timezone }));
    46→
    47→  const year = localDate.getFullYear();
    48→  const month = String(localDate.getMonth() + 1).padStart(2, '0');
    49→  const day = String(localDate.getDate()).padStart(2, '0');
    50→
    51→  return `${year}-${month}-${day}`;
    52→}
    53→
    54→/**
    55→ * Get year-month for directory structure: "YYYY-MM"
    56→ */
    57→export function getYearMonth(): string {
    58→  return getPSTDate().substring(0, 7);
    59→}
    60→
    61→/**
    62→ * Get ISO8601 timestamp with timezone offset
    63→ */
    64→export function getISOTimestamp(): string {
    65→  const timezone = getTimezone();
    66→  const date = new Date();
    67→  const localDate = new Date(date.toLocaleString('en-US', { timeZone: timezone }));
    68→
    69→  const year = localDate.getFullYear();
    70→  const month = String(localDate.getMonth() + 1).padStart(2, '0');
    71→  const day = String(localDate.getDate()).padStart(2, '0');
    72→  const hours = String(localDate.getHours()).padStart(2, '0');
    73→  const minutes = String(localDate.getMinutes()).padStart(2, '0');
    74→  const seconds = String(localDate.getSeconds()).padStart(2, '0');
    75→
    76→  // Calculate offset from UTC
    77→  const utcDate = new Date(date.toLocaleString('en-US', { timeZone: 'UTC' }));
    78→  const diffMs = localDate.getTime() - utcDate.getTime();
    79→  const diffHours = Math.floor(Math.abs(diffMs) / (1000 * 60 * 60));
    80→  const diffMins = Math.floor((Math.abs(diffMs) % (1000 * 60 * 60)) / (1000 * 60));
    81→  const sign = diffMs >= 0 ? '+' : '-';
    82→  const offset = `${sign}${String(diffHours).padStart(2, '0')}:${String(diffMins).padStart(2, '0')}`;
    83→
    84→  return `${year}-${month}-${day}T${hours}:${minutes}:${seconds}${offset}`;
    85→}
    86→
    87→/**
    88→ * Get timestamp formatted for filenames: "YYYY-MM-DD-HHMMSS"
    89→ */
    90→export function getFilenameTimestamp(): string {
    91→  const timezone = getTimezone();
    92→  const date = new Date();
    93→  const localDate = new Date(date.toLocaleString('en-US', { timeZone: timezone }));
    94→
    95→  const year = localDate.getFullYear();
    96→  const month = String(localDate.getMonth() + 1).padStart(2, '0');
    97→  const day = String(localDate.getDate()).padStart(2, '0');
    98→  const hours = String(localDate.getHours()).padStart(2, '0');
    99→  const minutes = String(localDate.getMinutes()).padStart(2, '0');
   100→  const seconds = String(localDate.getSeconds()).padStart(2, '0');
   101→
   102→  return `${year}-${month}-${day}-${hours}${minutes}${seconds}`;
   103→}
   104→
   105→/**
   106→ * Get timestamp components for custom formatting
   107→ */
   108→export function getPSTComponents(): {
   109→  year: number;
   110→  month: string;
   111→  day: string;
   112→  hours: string;
   113→  minutes: string;
   114→  seconds: string;
   115→} {
   116→  const timezone = getTimezone();
   117→  const date = new Date();
   118→  const localDate = new Date(date.toLocaleString('en-US', { timeZone: timezone }));
   119→
   120→  return {
   121→    year: localDate.getFullYear(),
   122→    month: String(localDate.getMonth() + 1).padStart(2, '0'),
   123→    day: String(localDate.getDate()).padStart(2, '0'),
   124→    hours: String(localDate.getHours()).padStart(2, '0'),
   125→    minutes: String(localDate.getMinutes()).padStart(2, '0'),
   126→    seconds: String(localDate.getSeconds()).padStart(2, '0'),
   127→  };
   128→}
   129→
   130→/**
   131→ * Get timezone string for display
   132→ */
   133→export function getTimezoneDisplay(): string {
   134→  const timezone = getTimezone();
   135→  const date = new Date();
   136→  return date.toLocaleString('en-US', { timeZone: timezone, timeZoneName: 'short' }).split(' ').pop() || timezone;
   137→}
