     1→/**
     2→ * ============================================================================
     3→ * TRACE EMITTER - Theory of Mind Capture System
     4→ * ============================================================================
     5→ *
     6→ * PURPOSE:
     7→ * Captures granular decision traces per-task, enabling retrospective analysis
     8→ * of how THE ALGORITHM made decisions. This is the "theory of mind" layer
     9→ * that allows us to understand and improve the algorithm by looking backwards.
    10→ *
    11→ * INTEGRATION:
    12→ * - All hooks import and use this library to emit events
    13→ * - Events append to Work/[task]/TRACE.jsonl
    14→ * - Nightly synthesis extracts patterns for system-level learning
    15→ *
    16→ * EVENT TYPES:
    17→ * - hook_start/hook_end: Hook lifecycle with duration
    18→ * - ai_call: Any AI model invocation (Haiku classifier, etc.)
    19→ * - decision: Explicit decision point with inputs/outputs
    20→ * - reasoning: Free-form reasoning chain
    21→ * - state_change: Phase transitions, status updates
    22→ * - tool_use: Tool execution summary
    23→ * - failure: Captured failure with context
    24→ * - loopback: Algorithm looped back to earlier phase
    25→ * - user_signal: User feedback (rating, interruption)
    26→ *
    27→ * SAFETY:
    28→ * - Atomic appends with size rotation (1MB per file)
    29→ * - Fail-open design (never blocks on trace errors)
    30→ * - No sensitive data in traces (prompts truncated)
    31→ *
    32→ * ============================================================================
    33→ */
    34→
    35→import { appendFileSync, existsSync, statSync, renameSync, mkdirSync } from 'fs';
    36→import { join, dirname } from 'path';
    37→import { findActiveWorkDir, type AlgorithmPhase } from './work-utils';
    38→
    39→// DEBUG flag
    40→const DEBUG = process.env.DEBUG_HOOKS === 'true';
    41→
    42→// Maximum size before rotation (1MB)
    43→const MAX_TRACE_SIZE = 1_000_000;
    44→
    45→// Maximum preview length for prompts (avoid leaking full content)
    46→const MAX_PREVIEW_LENGTH = 200;
    47→
    48→/**
    49→ * Trace event types
    50→ */
    51→export type TraceEventType =
    52→  | 'hook_start'      // Hook activation
    53→  | 'hook_end'        // Hook completion
    54→  | 'ai_call'         // Any AI invocation (classifier, summarizer)
    55→  | 'decision'        // Decision point with inputs/outputs
    56→  | 'reasoning'       // Free-form reasoning chain
    57→  | 'state_change'    // Phase transition, status update
    58→  | 'tool_use'        // Tool execution summary
    59→  | 'failure'         // Captured failure with context
    60→  | 'loopback'        // Algorithm looped back to earlier phase
    61→  | 'user_signal';    // User feedback (rating, interruption)
    62→
    63→/**
    64→ * Base trace event structure
    65→ */
    66→export interface TraceEvent {
    67→  ts: string;                    // ISO timestamp with ms precision
    68→  type: TraceEventType;          // Event type
    69→  hook?: string;                 // Hook name if hook-related
    70→  phase?: AlgorithmPhase;        // Current algorithm phase
    71→  data: Record<string, any>;     // Type-specific payload
    72→  duration_ms?: number;          // Execution time if measurable
    73→}
    74→
    75→/**
    76→ * Module-level state for current work directory
    77→ * This is set by hooks at startup and used for all emissions
    78→ */
    79→let currentWorkDir: string | null = null;
    80→
    81→/**
    82→ * Set the active work directory for trace emissions
    83→ * Called at hook startup after finding/creating work item
    84→ */
    85→export function setWorkDir(dir: string): void {
    86→  currentWorkDir = dir;
    87→  if (DEBUG) console.error('[TraceEmitter] Work dir set:', dir);
    88→}
    89→
    90→/**
    91→ * Get the current work directory (auto-detect if not set)
    92→ */
    93→export function getWorkDir(): string | null {
    94→  if (currentWorkDir) return currentWorkDir;
    95→
    96→  // Auto-detect from active work
    97→  const detected = findActiveWorkDir();
    98→  if (detected) {
    99→    currentWorkDir = detected;
   100→    if (DEBUG) console.error('[TraceEmitter] Auto-detected work dir:', detected);
   101→  }
   102→  return currentWorkDir;
   103→}
   104→
   105→/**
   106→ * Get the TRACE.jsonl path for current work directory
   107→ */
   108→function getTracePath(): string | null {
   109→  const workDir = getWorkDir();
   110→  if (!workDir) return null;
   111→  return join(workDir, 'TRACE.jsonl');
   112→}
   113→
   114→/**
   115→ * Rotate trace file if it exceeds size limit
   116→ */
   117→function rotateIfNeeded(tracePath: string): void {
   118→  try {
   119→    if (!existsSync(tracePath)) return;
   120→
   121→    const stats = statSync(tracePath);
   122→    if (stats.size > MAX_TRACE_SIZE) {
   123→      const archivePath = join(
   124→        dirname(tracePath),
   125→        `TRACE-${Date.now()}.jsonl`
   126→      );
   127→      renameSync(tracePath, archivePath);
   128→      if (DEBUG) console.error('[TraceEmitter] Rotated trace to:', archivePath);
   129→    }
   130→  } catch (e) {
   131→    if (DEBUG) console.error('[TraceEmitter] Rotation check failed:', e);
   132→  }
   133→}
   134→
   135→/**
   136→ * Core emit function - appends event to TRACE.jsonl
   137→ * Fail-open design: never throws, never blocks
   138→ */
   139→export function emit(event: Omit<TraceEvent, 'ts'>): void {
   140→  const tracePath = getTracePath();
   141→  if (!tracePath) {
   142→    if (DEBUG) console.error('[TraceEmitter] No work dir, skipping emit');
   143→    return;
   144→  }
   145→
   146→  const fullEvent: TraceEvent = {
   147→    ts: new Date().toISOString(),
   148→    ...event
   149→  };
   150→
   151→  try {
   152→    // Ensure directory exists
   153→    const dir = dirname(tracePath);
   154→    if (!existsSync(dir)) {
   155→      mkdirSync(dir, { recursive: true });
   156→    }
   157→
   158→    // Check for rotation
   159→    rotateIfNeeded(tracePath);
   160→
   161→    // Atomic append
   162→    appendFileSync(tracePath, JSON.stringify(fullEvent) + '\n');
   163→
   164→    if (DEBUG) console.error('[TraceEmitter] Emitted:', event.type, event.hook || '');
   165→  } catch (e) {
   166→    // Fail open - log but don't crash
   167→    if (DEBUG) console.error('[TraceEmitter] Write failed:', e);
   168→  }
   169→}
   170→
   171→// ============================================================================
   172→// Convenience Functions for Common Event Types
   173→// ============================================================================
   174→
   175→/**
   176→ * Emit hook_start event
   177→ * Call at the beginning of any hook's main function
   178→ */
   179→export function emitHookStart(
   180→  hookName: string,
   181→  trigger: string,
   182→  data?: Record<string, any>
   183→): void {
   184→  emit({
   185→    type: 'hook_start',
   186→    hook: hookName,
   187→    data: { trigger, ...data }
   188→  });
   189→}
   190→
   191→/**
   192→ * Emit hook_end event
   193→ * Call at the end of any hook's main function (in finally block)
   194→ */
   195→export function emitHookEnd(hookName: string, durationMs: number): void {
   196→  emit({
   197→    type: 'hook_end',
   198→    hook: hookName,
   199→    duration_ms: durationMs,
   200→    data: {}
   201→  });
   202→}
   203→
   204→/**
   205→ * Emit decision event
   206→ * Call at any explicit decision point (classifier output, routing decision)
   207→ */
   208→export function emitDecision(
   209→  hookName: string,
   210→  input: any,
   211→  output: any,
   212→  confidence?: number
   213→): void {
   214→  emit({
   215→    type: 'decision',
   216→    hook: hookName,
   217→    data: {
   218→      input: typeof input === 'string'
   219→        ? input.slice(0, MAX_PREVIEW_LENGTH)
   220→        : input,
   221→      output,
   222→      ...(confidence !== undefined && { confidence })
   223→    }
   224→  });
   225→}
   226→
   227→/**
   228→ * Emit ai_call event
   229→ * Call after any AI model invocation
   230→ */
   231→export function emitAiCall(
   232→  hookName: string,
   233→  model: string,
   234→  tokensIn: number,
   235→  tokensOut: number,
   236→  durationMs: number
   237→): void {
   238→  emit({
   239→    type: 'ai_call',
   240→    hook: hookName,
   241→    data: {
   242→      model,
   243→      tokens_in: tokensIn,
   244→      tokens_out: tokensOut
   245→    },
   246→    duration_ms: durationMs
   247→  });
   248→}
   249→
   250→/**
   251→ * Emit reasoning event
   252→ * Call to capture free-form reasoning chains
   253→ */
   254→export function emitReasoning(phase: AlgorithmPhase, content: string): void {
   255→  emit({
   256→    type: 'reasoning',
   257→    phase,
   258→    data: {
   259→      content: content.slice(0, 1000)  // Cap reasoning length
   260→    }
   261→  });
   262→}
   263→
   264→/**
   265→ * Emit state_change event
   266→ * Call on phase transitions or status updates
   267→ */
   268→export function emitStateChange(
   269→  phase: AlgorithmPhase,
   270→  from: string,
   271→  to: string,
   272→  trigger?: string
   273→): void {
   274→  emit({
   275→    type: 'state_change',
   276→    phase,
   277→    data: { from, to, ...(trigger && { trigger }) }
   278→  });
   279→}
   280→
   281→/**
   282→ * Emit tool_use event
   283→ * Call after significant tool executions
   284→ */
   285→export function emitToolUse(
   286→  toolName: string,
   287→  summary: Record<string, any>
   288→): void {
   289→  emit({
   290→    type: 'tool_use',
   291→    data: {
   292→      tool: toolName,
   293→      ...summary
   294→    }
   295→  });
   296→}
   297→
   298→/**
   299→ * Emit failure event
   300→ * Call when capturing any failure condition
   301→ */
   302→export function emitFailure(
   303→  phase: AlgorithmPhase,
   304→  error: string,
   305→  context?: Record<string, any>
   306→): void {
   307→  emit({
   308→    type: 'failure',
   309→    phase,
   310→    data: {
   311→      error,
   312→      ...(context && { context })
   313→    }
   314→  });
   315→}
   316→
   317→/**
   318→ * Emit loopback event
   319→ * Call when algorithm loops back to earlier phase
   320→ */
   321→export function emitLoopback(
   322→  from: AlgorithmPhase,
   323→  to: AlgorithmPhase,
   324→  reason: string
   325→): void {
   326→  emit({
   327→    type: 'loopback',
   328→    data: { from, to, reason }
   329→  });
   330→}
   331→
   332→/**
   333→ * Emit user_signal event
   334→ * Call when capturing user feedback or interruption
   335→ */
   336→export function emitUserSignal(
   337→  signalType: string,
   338→  content: any
   339→): void {
   340→  emit({
   341→    type: 'user_signal',
   342→    data: {
   343→      type: signalType,
   344→      content: typeof content === 'string'
   345→        ? content.slice(0, MAX_PREVIEW_LENGTH)
   346→        : content
   347→    }
   348→  });
   349→}
   350→
   351→/**
   352→ * Higher-order function to wrap a hook with trace instrumentation
   353→ * Automatically emits hook_start and hook_end events
   354→ */
   355→export function withTracing<T>(
   356→  hookName: string,
   357→  trigger: string,
   358→  fn: () => Promise<T>
   359→): Promise<T> {
   360→  const startTime = Date.now();
   361→  emitHookStart(hookName, trigger);
   362→
   363→  return fn()
   364→    .finally(() => {
   365→      emitHookEnd(hookName, Date.now() - startTime);
   366→    });
   367→}
