   272→    const titleWithSuffix = state !== 'normal' ? `${title}…` : title;
   273→    const truncated = titleWithSuffix.length > 50 ? titleWithSuffix.slice(0, 47) + '…' : titleWithSuffix;
   274→    const escaped = truncated.replace(/'/g, "'\\''");
