async function getCurrentDate(): Promise<string> {
  try {
    // Cross-platform date formatting using Intl API instead of Unix date command
    const timezone = process.env.TIME_ZONE || 'America/Los_Angeles';
    const now = new Date();

    const formatter = new Intl.DateTimeFormat('en-US', {
      timeZone: timezone,
      year: 'numeric',
      month: '2-digit',
      day: '2-digit',
      hour: '2-digit',
      minute: '2-digit',
      second: '2-digit',
      timeZoneName: 'short',
      hour12: false
    });

    // Format: YYYY-MM-DD HH:MM:SS TZ
    const parts = formatter.formatToParts(now);
    const year = parts.find(p => p.type === 'year')?.value || '';
    const month = parts.find(p => p.type === 'month')?.value || '';
    const day = parts.find(p => p.type === 'day')?.value || '';
    const hour = parts.find(p => p.type === 'hour')?.value || '';
    const minute = parts.find(p => p.type === 'minute')?.value || '';
    const second = parts.find(p => p.type === 'second')?.value || '';
    const tzName = parts.find(p => p.type === 'timeZoneName')?.value || '';

    return `${year}-${month}-${day} ${hour}:${minute}:${second} ${tzName}`;
  } catch (error) {
    console.error('Failed to get current date:', error);
    return new Date().toISOString();
  }
}

